function ApiPoller() {
  const [url, setUrl] = React.useState('REPLACE_WITH_URL');
  const [interval, setInterval] = React.useState(60);
  const [headers, setHeaders] = React.useState('');
  const [last, setLast] = React.useState(null);
  const [prev, setPrev] = React.useState(null);
  const [running, setRunning] = React.useState(false);
  const [ts, setTs] = React.useState(null);
  const [error, setError] = React.useState('');
  React.useEffect(() => {
    if (!running) return;
    let alive = true;
    const tick = async () => {
      try {
        const opts = {};
        if (headers) { try { opts.headers = JSON.parse(headers); } catch {} }
        const r = await fetch(url, opts);
        const text = await r.text();
        let body; try { body = JSON.parse(text); } catch { body = text; }
        if (!alive) return;
        setPrev(last); setLast(body); setTs(new Date()); setError('');
      } catch (e) { setError(String(e?.message||e)); }
    };
    tick();
    const id = window.setInterval(tick, Math.max(5, interval) * 1000);
    return () => { alive = false; window.clearInterval(id); };
  }, [running, url, interval, headers]);
  const changed = JSON.stringify(prev) !== JSON.stringify(last);
  return (
    <div style={{padding:12,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',gap:6}}>
      <input value={url} onChange={e=>setUrl(e.target.value)} placeholder="https://..." style={{padding:'6px 10px',border:'1px solid #ccc',borderRadius:6,fontSize:12,fontFamily:'monospace'}}/>
      <div style={{display:'flex',gap:6}}>
        <input type="number" value={interval} onChange={e=>setInterval(Number(e.target.value)||60)} placeholder="sec" style={{width:80,padding:'6px 8px',border:'1px solid #ccc',borderRadius:6,fontSize:12}}/>
        <input value={headers} onChange={e=>setHeaders(e.target.value)} placeholder='{"Authorization":"Bearer …"}' style={{flex:1,padding:'6px 8px',border:'1px solid #ccc',borderRadius:6,fontSize:11,fontFamily:'monospace'}}/>
        <button onClick={()=>setRunning(!running)} style={{padding:'6px 14px',border:'none',borderRadius:6,background:running?'#FF3B30':'#34C759',color:'#fff',cursor:'pointer'}}>{running?'Stop':'Start'}</button>
      </div>
      <div style={{fontSize:11,color:'#888'}}>Last poll: {ts ? ts.toLocaleTimeString() : '—'} {prev !== null && (changed ? <span style={{color:'#FF9500'}}>· changed!</span> : <span style={{color:'#34C759'}}>· no change</span>)}</div>
      {error && <div style={{color:'#FF3B30',fontSize:12}}>{error}</div>}
      <pre style={{flex:1,overflow:'auto',background:'#1e1e1e',color:'#d4d4d4',padding:10,borderRadius:8,fontSize:11,margin:0}}>{last !== null ? (typeof last === 'string' ? last : JSON.stringify(last, null, 2)) : 'No data yet.'}</pre>
    </div>
  );
}
render(<ApiPoller/>);
